INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVN5931C774810HDR72', 'order-flow-imbalance-ofi-mid-price-prediction', 'Order Flow Imbalance (OFI) mid-price prediction', 'microstructure', 'IDEA', 'Binance perp top-of-book OFI over 1-5 minutes moves mid-price in the same direction.', 'OFI reflects one-sided pressure that market makers must absorb before re-quoting, creating short-lived directional drift.', 'Only shown via correlation (0.94) between futures mid-price and spot order-book imbalance, not a walk-forward backtest.', '[{"kind":"paper","ref":"arXiv:2602.00776","note":"Explainable Patterns in Cryptocurrency Microstructure"}]', 'pdf_seed', 'EC-001', '{"originality":3,"feasibility":2,"verifiability":3,"lowCost":2,"dataEase":4,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPQASVA4CQSV1F6V7Q', 'vpin-based-jump-prediction', 'VPIN-based jump prediction', 'microstructure', 'IDEA', 'Elevated VPIN (order-flow toxicity) precedes price jumps with positive serial correlation.', 'Informed-trader order flow accumulates before liquidity providers reprice, so toxicity measures lead realized jumps.', 'VPIN''s volume-bucketing parameterization is a known source of look-ahead/overfitting risk in retrospective studies.', '[{"kind":"paper","ref":"ScienceDirect S0275531925004192","note":"VPIN significantly predicts future price jumps"}]', 'pdf_seed', 'EC-002', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPHWYTNG1SFVDAZ8HS', 'cross-exchange-ofi-lead-lag-coinbase-binance', 'Cross-exchange OFI lead-lag (Coinbase -> Binance)', 'microstructure', 'IDEA', 'Coinbase spot order flow leads Binance futures order flow by a few seconds.', 'Coinbase''s US-hours liquidity concentration lets its flow inform Binance''s global futures market before arbitrage closes the gap.', 'Lead-lag windows this short are highly sensitive to venue latency and may have decayed since data collection.', '[{"kind":"internal","ref":"Granger causality analysis","note":"Coinbase vs Binance OFI, second-level ticks"}]', 'pdf_seed', 'EC-003', '{"originality":4,"feasibility":2,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPJQMMNN73Z2P4J6D7', 'order-book-depth-regression-on-spread-returns', 'Order-book depth regression on spread returns', 'microstructure', 'IDEA', 'Binance depth-imbalance regressions forecast very short-horizon spread returns.', 'Market-maker inventory skew shows up in depth before it shows up in trades.', 'Statistical significance of the regression coefficients has not been established.', '[{"kind":"internal","ref":"Binance depth snapshots","note":"spread z-score regression"}]', 'pdf_seed', 'EC-004', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPWGSY9SYV7J2NY1QP', 'cvd-price-divergence', 'CVD / price divergence', 'microstructure', 'IDEA', 'Cumulative Volume Delta diverging from price (delta up, price flat/down) precedes a reversal.', 'Persistent one-sided taker aggression that isn''t reflected in price implies passive absorption that eventually breaks.', 'CVD''s absolute level is non-stationary; divergence detection is sensitive to the normalization window chosen.', '[{"kind":"internal","ref":"Binance aggTrades CVD","note":"divergence detection heuristic"}]', 'pdf_seed', 'EC-005', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPEWYP4FNKH0C0W8EV', 'liquidation-cascade-rebound', 'Liquidation-cascade rebound', 'liquidation', 'IDEA', 'After a large 24h liquidation z-score spike coinciding with an OI drop, BTC rebounds over the next 24-72h.', 'Liquidations are price-insensitive forced selling/buying; once the deleveraging is exhausted, the price snaps back toward fair value (Brunnermeier & Pedersen liquidity spiral).', 'Binance forceOrder liquidation feed is a 2021+ sampled stream, not a complete record — magnitude estimates are approximate.', '[{"kind":"paper","ref":"SSRN 5611392","note":"Oct 2025 cascade analysis, GARCH alpha+beta approx 0.90"}]', 'pdf_seed', 'EC-006', '{"originality":4,"feasibility":4,"verifiability":3,"lowCost":3,"dataEase":3,"durability":4,"humanOps":4}', 1782950400000, 1782950400000);
