VALUES ('01KWHQ6YVPW7KQRSF5PNQVBXE6', '01KWHQ6YVPEWYP4FNKH0C0W8EV', '1.0.0', '{"when":{"and":[{"cmp":[{"feature":"liq_long_z_24h"},">",3]},{"cmp":[{"feature":"oi_chg_24h"},"<",-5]}]},"entry":{"delay_bars":1,"price":"open"},"exit":{"horizon":"72h"},"direction":"long"}', '{}', 'BTCUSDT.BINANCE.PERP', 'long', '72h', '{"taker_bps":4,"slippage_bps":2,"funding_included":false}', 'Initial PDF-seed version (docs/09 §3)', 1782950400000, 1);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPQCXPECAKG0HEMX44', 'funding-rate-mean-reversion', 'Funding rate mean reversion', 'liquidation', 'IDEA', 'Extreme funding rates (top/bottom percentile) revert over the following 8-72h.', 'Overcrowded leveraged positioning becomes self-defeating once the funding cost outweighs the directional conviction.', 'Cited effect size is modest (beta approx -0.087, R^2 approx 0.003) — most of the variance is unexplained.', '[{"kind":"internal","ref":"Fulgur Ventures / SSRN 5576424","note":"BitMEX funding -> next 8h BTC return"}]', 'pdf_seed', 'EC-007', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPCAY5C32SPXNVVY67', 'liquidation-heatmap-magnet', 'Liquidation heatmap magnet', 'liquidation', 'IDEA', 'Price gravitates toward dense liquidation-cluster levels within a session.', 'Market makers and liquidity hunters have an incentive to trigger nearby stop/liquidation clusters, pulling price toward them.', 'Precise heatmap granularity requires paid CoinGlass data; free-tier approximations are coarse.', '[{"kind":"internal","ref":"CoinGlass heatmap construction","note":"OI + liquidation distance"}]', 'pdf_seed', 'EC-008', '{"originality":4,"feasibility":3,"verifiability":2,"lowCost":2,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVP1MYCEBR6P8MR7B05', 'open-interest-price-divergence', 'Open interest / price divergence', 'liquidation', 'IDEA', 'Price rising while OI falls (short covering, not new longs) is a weaker, less durable rally than price+OI both rising.', 'New-money-driven rallies (rising OI) reflect fresh conviction; covering-driven rallies run out of fuel once shorts are closed.', 'Classifying rally ''quality'' after the fact is easier than identifying it causally in real time.', '[{"kind":"internal","ref":"Binance OI + CoinGlass","note":"OI/return divergence classification"}]', 'pdf_seed', 'EC-009', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQH3VA2NDGJKY5HC6Z', 'three-exchange-basis-convergence', 'Three-exchange basis convergence', 'liquidation', 'IDEA', 'When Binance/OKX/Deribit futures basis diverges beyond a threshold, it converges back within days to weeks.', 'Basis is a proxy for aggregate speculative sentiment; cross-exchange arbitrage bounds how far it can persistently diverge.', 'CME basis normalization (25% in 2024 to near-zero in 2025 per CF Benchmarks) suggests the historical relationship may be regime-dependent.', '[{"kind":"internal","ref":"CF Benchmarks basis series","note":"cross-venue basis convergence"}]', 'pdf_seed', 'EC-010', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQ6YVC6DG8MCRYKGNG', 'top-trader-long-short-ratio-extremes', 'Top-trader long/short ratio extremes', 'liquidation', 'IDEA', 'Extreme top-trader L/S account ratios precede reversals.', 'Even ''smart money'' cohorts become crowded at extremes, and crowded positioning is fragile to any adverse catalyst.', 'The account-ratio metric weights accounts equally regardless of size, which can misrepresent actual capital positioning.', '[{"kind":"internal","ref":"Binance topLongShortAccountRatio","note":"extreme-ratio reversal"}]', 'pdf_seed', 'EC-011', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQHT3N15QVZG0ANNWN', 'funding-settlement-microstructure-pattern', 'Funding settlement microstructure pattern', 'liquidation', 'IDEA', 'Positioning adjustments immediately before 00:00/08:00/16:00 UTC funding settlement create a predictable micro pattern.', 'Traders adjust positions just before settlement to avoid paying/collect funding, creating mechanical, recurring flow.', 'Effect size at 1-minute granularity is small and may not clear transaction costs consistently.', '[{"kind":"internal","ref":"Binance 1m + fundingRate","note":"pre/post settlement microstructure"}]', 'pdf_seed', 'EC-012', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQWNTEFMGN3A078EGQ', 'variance-risk-premium-vrp-selling', 'Variance risk premium (VRP) selling', 'options', 'IDEA', 'Deribit 30-day implied vol (DVOL) systematically exceeds realized vol, so short-vol carries positive expected value.', 'Persistent hedging demand from option buyers pays a structural premium to sellers, much like equity index VRP.', 'Tail risk is severe and asymmetric — VRP-selling strategies can suffer catastrophic drawdowns in vol spikes (e.g. Mar 2020).', '[{"kind":"paper","ref":"Amberdata/Deribit Insights","note":"IV>RV ~70% of the time since 2019"},{"kind":"paper","ref":"arXiv:2410.15195","note":"Bitcoin VRP exceeds S&P 500''s"}]', 'pdf_seed', 'EC-013', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR935QGJ073489N38F', '25-delta-skew-as-a-realized-vol-forecaster', '25-delta skew as a realized-vol forecaster', 'options', 'IDEA', 'Option skew predicts next-period realized volatility (not returns) at weekly frequency.', 'Skew encodes the market''s tail-hedging demand, which correlates with near-term realized turbulence even when it says nothing about direction.', 'The same study finds skew has no predictive power for returns, only for volatility — direction-based use would be a misapplication.', '[{"kind":"paper","ref":"Chen, Deng & Nie 2024, Operations Research Letters","note":"skew forecasts weekly RV, not returns"}]', 'pdf_seed', 'EC-014', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRAJ6S0F9DS7FFD854', '25-delta-risk-reversal-selling', '25-delta risk-reversal selling', 'options', 'IDEA', 'Selling the 25-delta risk reversal (short calls, long puts, or vice versa depending on skew sign) has the best risk-adjusted return among simple option overlays.', 'Persistent one-sided directional hedging demand keeps skew rich, similar to the VRP mechanism.', 'The source result appears to be dominated by the March 2020 ''Black Thursday'' tail event; excluding that outlier needs separate verification.', '[{"kind":"paper","ref":"Amberdata","note":"risk-reversal selling has best risk-adjusted return"}]', 'pdf_seed', 'EC-015', '{"originality":3,"feasibility":2,"verifiability":2,"lowCost":2,"dataEase":4,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRT5MN93SS5G40ESG9', 'dealer-gamma-exposure-gex-regime', 'Dealer gamma exposure (GEX) regime', 'options', 'IDEA', 'Dealer gamma positioning (long/short gamma regime) predicts volatility amplification vs. dampening.', 'In a short-gamma regime, dealer hedging is pro-cyclical (buys rallies, sells dips), amplifying moves; long-gamma dampens them.', 'GEX is a modeled/estimated quantity, not directly observable, and different providers'' estimates can disagree materially.', '[{"kind":"paper","ref":"Bitfinex Alpha","note":"2026 dealer gamma estimate, ~-143,000 BTC net"}]', 'pdf_seed', 'EC-016', '{"originality":5,"feasibility":2,"verifiability":2,"lowCost":3,"dataEase":3,"durability":4,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRWKX10D9GR41BN0S2', 'options-expiry-sq-max-pain-gravitational-pull', 'Options expiry (SQ) / max-pain gravitational pull', 'options', 'IDEA', 'Price drifts toward the max-pain strike before large options expiries, then can reverse sharply once the pin risk unwinds.', 'Dealer hedging flow near a large expiry creates a pull toward the strike that minimizes aggregate option payout.', 'The ''pin'' effect competes with dealer gamma regime (EC-016); the two need to be studied jointly rather than in isolation.', '[{"kind":"internal","ref":"Deribit OI + CoinGlass","note":"expiry-window volatility/return decomposition"}]', 'pdf_seed', 'EC-017', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRV37W1JBVKEMPSHAQ', '21-00-23-00-utc-intraday-drift', '21:00-23:00 UTC intraday drift', 'seasonality', 'IDEA', 'BTC has a statistically positive return in the 21:00-23:00 UTC window, in a bull (above 200-day SMA) regime.', 'US-afternoon/evening liquidity and flow patterns recur daily; QuantPedia documents +33% annualized return isolating this window.', 'Pure calendar-effect data mining risk is high; must be confirmed out of the 2020-heavy sample and re-verified against ETF-era flow changes.', '[{"kind":"paper","ref":"QuantPedia: The Seasonality of Bitcoin","note":"21:00-23:00 UTC window, ~33% annualized"}]', 'pdf_seed', 'EC-018', '{"originality":3,"feasibility":5,"verifiability":5,"lowCost":2,"dataEase":5,"durability":3,"humanOps":5}', 1782950400000, 1782950400000);
