INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR5164JVBPS8TQS657', 'monday-asia-open-effect', 'Monday Asia-open effect', 'seasonality', 'IDEA', 'BTC shows a recurring directional tendency around the Monday 19:00 UTC (Asia funding-market open) window.', 'Weekend illiquidity resolves as Asian institutional flow returns at the start of the week.', 'Effect timing was matched to a 2020-era study; needs reverification post-ETF given shifted market structure.', '[{"kind":"paper","ref":"Concretum Group: Monday Asia Open Effect","note":"matches 2020-era timing"}]', 'pdf_seed', 'EC-019', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRCHNSMH1AMHXSW7P8', 'nyse-open-day-of-week-effect', 'NYSE-open day-of-week effect', 'seasonality', 'IDEA', 'Return decomposition into intraday vs. overnight legs around NYSE open shows a day-of-week pattern with overnight-heavy weeks.', 'Traditional-market participants'' hedging/rebalancing bleeds into crypto trading hours at the NYSE open.', 'Intraday/overnight decomposition is sensitive to how the boundary is defined.', '[{"kind":"paper","ref":"Padysak & Vojtko, paperswithbacktest","note":"NYSE-open overnight/intraday decomposition"}]', 'pdf_seed', 'EC-020', '{"originality":4,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRFDG5DC9NN2RHRW74', 'cme-futures-gap-fill', 'CME futures gap fill', 'seasonality', 'IDEA', 'CME BTC futures gaps (Friday close vs. Sunday open) fill within a bounded window at a high rate, especially small gaps.', 'CME trades a five-day week while spot trades 24/7; the mismatch mechanically creates gaps that magnet-fill as spot/futures arbitrage re-links the two.', 'Large gaps (>5%) fill far less reliably (~52%) than small ones (~92% for <2% gaps); position sizing must respect this.', '[{"kind":"paper","ref":"Phemex / Bitget gap-fill statistics","note":"~77% overall fill rate 2018-2026; <2% gaps ~92% within 30 days"}]', 'pdf_seed', 'EC-021', '{"originality":3,"feasibility":5,"verifiability":5,"lowCost":4,"dataEase":4,"durability":4,"humanOps":5}', 1782950400000, 1782950400000);
