INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRS03P0X9TA0BWVJFA', 'month-end-rebalance-flow', 'Month-end rebalance flow', 'seasonality', 'IDEA', 'BTC shows recurring flow around month-end, consistent with institutional rebalancing.', 'Index-tracking and multi-asset portfolios rebalance on a monthly cycle, creating recurring calendar-linked flow.', 'This is more speculative than the other seasonality candidates; needs a dedicated event study before further investment.', '[{"kind":"internal","ref":"Binance daily return + calendar","note":"month-end return decomposition"}]', 'pdf_seed', 'EC-022', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRVWB12C9FHM5A2N66', 'weekly-breakout-continuation', 'Weekly breakout continuation', 'seasonality', 'IDEA', 'Breakouts from the prior week''s range tend to continue rather than mean-revert.', 'Weekly ranges concentrate accumulated positioning; a genuine breakout reflects a real supply/demand shift rather than noise.', 'Breakout-continuation strategies are a well-known crowded style; edge durability is uncertain.', '[{"kind":"internal","ref":"Binance weekly range breakout","note":"continuation-vs-reversion study"}]', 'pdf_seed', 'EC-023', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRN82D80ASMW3WCVY5', 'coinbase-premium-as-an-etf-flow-proxy', 'Coinbase premium as an ETF-flow proxy', 'etf_flow', 'IDEA', 'The Coinbase/Binance price premium correlates with US spot ETF net flows and can serve as a real-time proxy before official flow data is published.', 'Coinbase is the primary US institutional on-ramp and ETF authorized-participant venue, so its premium reflects US buying pressure ahead of official reporting.', 'Correlation with ETF flow is moderate (R^2 approx 0.32), so the proxy is noisy on any single day.', '[{"kind":"internal","ref":"ainvest analysis","note":"Coinbase premium vs US ETF net flow, R^2~0.32"}]', 'pdf_seed', 'EC-024', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR06E3Q76X0E8SXK3X', 'etf-t-1-sell-pressure', 'ETF T+1 sell pressure', 'etf_flow', 'IDEA', 'Large ETF creation/redemption activity produces spot sell pressure via Coinbase Prime the following trading day (T+1 settlement).', 'Authorized participants source/dispose of BTC through Coinbase Prime on a T+1 cycle, so flow effects on spot lag the official ETF flow print by one day.', 'Evidence is a single illustrative case (IBIT ~2,791 BTC), not a systematic backtest.', '[{"kind":"internal","ref":"SoSoValue/ETF flow + Coinbase next-day return","note":"T+1 sell-pressure case study"}]', 'pdf_seed', 'EC-025', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRJPEFR8P6ZWQG939Q', 'etf-flow-sentiment-divergence', 'ETF flow / sentiment divergence', 'etf_flow', 'IDEA', 'When Fear & Greed is fearful but ETF inflows continue, that divergence (institutions accumulating into retail fear) precedes upside.', 'Institutional ETF buyers on multi-day mandates are less reactive to short-term sentiment swings than retail, so their continued buying against fear is informative.', 'Sentiment-vs-flow divergence signals are inherently low-frequency and sample-limited (ETFs only exist since 2024).', '[{"kind":"internal","ref":"alternative.me F&G + ETF flow","note":"divergence-conditioned forward return"}]', 'pdf_seed', 'EC-026', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRRJ515K03P77HTCB2', 'cme-cot-positioning-reversal', 'CME COT positioning reversal', 'etf_flow', 'IDEA', 'Extreme CFTC Commitment of Traders net positioning (Leveraged Funds vs. Asset Managers) precedes reversals.', 'Leveraged funds represent short-term speculative positioning that becomes a forced-unwind risk once sufficiently crowded.', 'COT data is weekly and reported with a lag, limiting timing precision.', '[{"kind":"internal","ref":"CFTC COT + CoinGlass CFTC","note":"extreme-positioning reversal"}]', 'pdf_seed', 'EC-027', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR68HKHY18WDHW4XVA', 'exchange-netflow-signal', 'Exchange netflow signal', 'onchain', 'IDEA', 'Large net inflows to exchanges precede downside (deposit-to-sell); net outflows precede upside (accumulation).', 'Moving coins onto an exchange is a necessary precondition for selling on that exchange, so netflow is a leading indicator of intent.', 'Free-tier data cannot label exchange wallets precisely, limiting classification accuracy versus paid providers.', '[{"kind":"internal","ref":"Glassnode (free tier) / CryptoQuant","note":"netflow-conditioned forward return"}]', 'pdf_seed', 'EC-028', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":2,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR286VYPR0C8FWVGKZ', 'whale-alert-transfer-reaction', 'Whale Alert transfer reaction', 'onchain', 'IDEA', 'Large publicized whale transfers spark a short-horizon (6-24h) volatility/return spillover as the market reacts to the alert.', 'Whale Alert''s wide Telegram distribution makes large transfers a shared, salient signal that triggers a reflexive trading reaction, independent of the transfer''s true intent.', 'The spillover is a reaction to the *alert* being seen, not necessarily to the underlying transfer''s economic meaning — a purely reflexive, possibly decaying effect.', '[{"kind":"paper","ref":"Magner & Sanhueza 2025, Finance Research Letters","note":"spillover rises from 2.78% at 1h to 4.68% at 24h"}]', 'pdf_seed', 'EC-029', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRJ3KYB5JNFZMPT1R6', 'exchange-whale-ratio', 'Exchange whale ratio', 'onchain', 'IDEA', 'A high ratio of top-10-wallet inflow to total exchange inflow (concentration among whales) precedes distribution/selling.', 'Concentrated large-wallet deposits are more likely to represent a single actor''s imminent sell decision than broad-based small-wallet deposits.', 'Claimed threshold (''>85% precedes selling'') needs independent verification; the source notes it as anecdotal.', '[{"kind":"internal","ref":"CryptoQuant Exchange Whale Ratio","note":"ratio-conditioned forward return"}]', 'pdf_seed', 'EC-030', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":2,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRNM0Z5C6SXQ14QF0B', 'usdt-mint-event-drift', 'USDT mint event drift', 'stablecoin', 'IDEA', 'Large USDT Treasury mint events produce a positive BTC drift over 5-30 minutes that decays after 60 minutes; burns show no comparable (asymmetric) effect.', 'New stablecoin issuance is a precondition for fresh exchange buying power; the FOMO/anticipation reaction to a well-publicized mint (via Whale Alert) amplifies the pure liquidity effect.', 'Griffin & Shams'' (2020) Tether-manipulation hypothesis has a published rebuttal (Wei 2018) finding minting cannot move price — the mechanism is contested, so treat as a short-horizon (<=60min) event effect, not a structural thesis.', '[{"kind":"paper","ref":"Saggu 2022, Finance Research Letters vol.49","note":"+0.24% at 5min, +0.68% at 30min, decaying by 60min"}]', 'pdf_seed', 'EC-031', '{"originality":5,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);
INSERT INTO edge_versions (version_id, edge_id, semver, signal_spec, params, instrument_id, direction, horizon, cost_model, changelog, created_at, is_current)
VALUES ('01KWHQ6YVSDHM8C2VAT7ZEPY27', '01KWHQ6YVRNM0Z5C6SXQ14QF0B', '1.0.0', '{"when":{"event":{"type":"usdt_mint","min_magnitude":1000000000}},"entry":{"delay_bars":1,"price":"open"},"exit":{"horizon":"30m"},"direction":"long"}', '{}', 'BTCUSDT.BINANCE.PERP', 'long', '30m', '{"taker_bps":4,"slippage_bps":2,"funding_included":false}', 'Initial PDF-seed version (docs/09 §3)', 1782950400000, 1);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSF5R19CSNV9NABF1B', 'stablecoin-supply-ratio-ssr-low-reversal', 'Stablecoin Supply Ratio (SSR) low reversal', 'stablecoin', 'IDEA', 'A low SSR (large stablecoin ''dry powder'' relative to BTC market cap) precedes upside as that capital deploys.', 'Stablecoin balances represent capital parked on the sidelines ready to buy; when that pool is large relative to BTC''s cap, incremental buying power is high.', 'SSR is a slow-moving macro-liquidity indicator; timing precision at anything shorter than weeks is unlikely.', '[{"kind":"internal","ref":"CryptoQuant / DefiLlama SSR","note":"low-SSR-conditioned forward return"}]', 'pdf_seed', 'EC-032', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSWRHDSDAKKD59W7VR', 'stablecoin-issuance-acceleration', 'Stablecoin issuance acceleration', 'stablecoin', 'IDEA', 'An accelerating (not just positive) growth rate in total stablecoin supply precedes BTC inflow over days to weeks.', 'Acceleration (second derivative) captures a regime change in capital formation intent more cleanly than the level or first-difference alone.', 'DefiLlama''s stablecoin supply series is itself subject to periodic revisions (bitemporal handling required, docs/02 §1).', '[{"kind":"internal","ref":"DefiLlama stablecoin supply, second derivative","note":"acceleration-conditioned forward return"}]', 'pdf_seed', 'EC-033', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSWJWV9Q8RNYTVWK14', 'usdt-depeg-risk-off-signal', 'USDT depeg risk-off signal', 'stablecoin', 'IDEA', 'USDT trading meaningfully below $1 (depeg) precedes a BTC decline as capital flees stablecoins broadly (flight to safety away from crypto, not into BTC).', 'A stablecoin depeg signals systemic/counterparty stress in crypto market infrastructure, prompting broad de-risking rather than rotation.', 'Depeg events are rare and each has idiosyncratic causes (e.g., banking-sector contagion in 2023); generalizability across events is unproven.', '[{"kind":"internal","ref":"Binance USDT/USDC + CoinGecko","note":"depeg-event forward return"}]', 'pdf_seed', 'EC-034', '{"originality":3,"feasibility":4,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSE8HB7Z339A4YZ93A', 'nasdaq-cross-asset-regime-linkage', 'Nasdaq cross-asset regime linkage', 'cross_asset', 'IDEA', 'BTC-Nasdaq correlation strengthens in risk-off regimes; the correlation regime itself (not the raw correlation) is informative.', 'As ETF ownership has grown, BTC increasingly trades as a high-beta macro-risk asset during stress, tightening its equity linkage.', 'A Chow test finds a structural break around ETF approval, meaning the pre/post relationship cannot be pooled naively.', '[{"kind":"paper","ref":"arXiv:2512.12815","note":"Chow test structural break, BTC-S&P500, p=0.0000"}]', 'pdf_seed', 'EC-035', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSKDN6C253ER5Q5NSC', 'dxy-correlation-regime', 'DXY correlation regime', 'cross_asset', 'IDEA', 'BTC/DXY correlation is regime-dependent and only informative for direction while the regime is stably negative.', 'Dollar strength/weakness is a standard macro-liquidity proxy, but the BTC linkage strengthens/weakens with the prevailing macro narrative.', 'Correlation dropped from ~0.7 (2014-2020) to ~0.45 recently per JPMorgan (2026); using this without regime-conditioning would be unstable.', '[{"kind":"internal","ref":"FRED DXY + Binance, OSL / JPMorgan commentary","note":"correlation regime shift"}]', 'pdf_seed', 'EC-036', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSYCACKJSF9N1EJ35J', 'global-m2-liquidity-linkage', 'Global M2 liquidity linkage', 'cross_asset', 'IDEA', 'Changes in global M2 money supply lead BTC price with a multi-week lag, as a liquidity-driven risk asset.', 'BTC behaves as a liquidity-sensitive, long-duration risk asset, so aggregate money-supply expansion/contraction should lead it the way it leads other risk assets.', 'M2 data is low-frequency (monthly) and revised, making this only useful as a slow-moving conditioning variable, not a standalone signal.', '[{"kind":"internal","ref":"FRED M2 + TradingEconomics + Binance","note":"lagged M2-BTC relationship"}]', 'pdf_seed', 'EC-037', '{"originality":3,"feasibility":3,"verifiability":2,"lowCost":2,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTQ6SX1BZGND4KWB3G', 'round-number-price-clustering', 'Round-number price clustering', 'behavioral', 'IDEA', 'Prices cluster at round numbers ($1,000 increments) due to anchoring and stop/limit placement, but returns after touching a round number show no significant pattern.', 'Anchoring bias (Harris 1991-style round-number effect) drives order placement to cluster at round levels.', 'The source paper explicitly finds no significant return pattern after round-number touches — clustering is real, but not directly tradeable as stated.', '[{"kind":"paper","ref":"Urquhart 2017, Economics Letters vol.159","note":"10.81% of Bitstamp prices end in 00; no significant post-touch return pattern"}]', 'pdf_seed', 'EC-038', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTZJADX51JTNYEGW01', 'price-momentum-continuation', 'Price momentum continuation', 'behavioral', 'IDEA', 'Recent multi-day/weekly momentum continues rather than reverts, driven by attention and FOMO/short-covering dynamics.', 'Rising attention begets more attention (media, social, search) which begets more buying, a reflexive momentum loop distinct from fundamentals.', 'Momentum is one of the most widely exploited styles in all of finance; crowding risk is high and durability is uncertain.', '[{"kind":"internal","ref":"Binance daily/weekly momentum","note":"continuation-conditioned forward return"}]', 'pdf_seed', 'EC-039', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTJJ1D8429KH761MYA', 'google-trends-overheat-fomo-fade', 'Google Trends overheat / FOMO fade', 'behavioral', 'IDEA', 'A sharp spike in ''Bitcoin'' search volume marks retail FOMO and precedes a local top / pullback.', 'Retail search interest peaks near euphoric tops as media coverage and word-of-mouth attention lag the actual price move.', 'Prior literature (arXiv:1408.1494) finds search spikes preceded *declines*, but the causal direction (search causing price vs. price causing search) is unresolved.', '[{"kind":"paper","ref":"arXiv:1408.1494","note":"search-volume spikes precede price declines"}]', 'pdf_seed', 'EC-040', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVT2R9FZGZBDA9KJ6QM', 'pre-fomc-drift', 'Pre-FOMC drift', 'event', 'IDEA', 'BTC rises the day before an FOMC announcement and falls on the announcement day itself.', 'Pre-announcement risk premium / information-leakage dynamics (Cieslak, Morse & Vissing-Jorgensen 2019) documented in equities extend to BTC''s now-more-macro-linked behavior.', 'Effect size (~+0.96% pre-day, ~-1% announcement day) is modest relative to typical daily BTC volatility.', '[{"kind":"paper","ref":"Pyo & Lee 2020, Finance Research Letters vol.37","note":"+0.96% day before, -1% on announcement day"}]', 'pdf_seed', 'EC-041', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTTGM77H1CZESBTZZY', 'sell-the-news-fomc-drift', '''Sell the news'' FOMC drift', 'event', 'IDEA', 'BTC tends to decline in the 48h after an FOMC announcement, regardless of the actual decision content.', 'Pre-positioned expectations (''buy the rumor'') unwind mechanically once the event passes, independent of whether the news itself was hawkish or dovish.', 'Cited support (7 of 8 2025 FOMC meetings) is a small, recency-dependent sample from a single secondary source, not an independently reproduced study.', '[{"kind":"internal","ref":"Coinmonks analysis","note":"7 of 8 2025 FOMC meetings showed post-announcement decline"}]', 'pdf_seed', 'EC-042', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":2,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTMPCX41EFP9QVDXC5', 'cpi-macro-print-volatility-compression', 'CPI / macro-print volatility compression', 'event', 'IDEA', 'BTC realized volatility compresses ahead of major macro data prints (CPI, PPI, FOMC) and expands afterward.', 'Pre-print positioning caution suppresses realized moves; the print''s resolution of uncertainty releases pent-up volatility.', 'BTC vol responds meaningfully to only about 10 of 29 tested macro indicators — most prints show no measurable effect.', '[{"kind":"paper","ref":"ScienceDirect S1059056025006720","note":"significant vol response to CPI/PPI/FOMC among 29 tested indicators"}]', 'pdf_seed', 'EC-043', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTD1AHQZKYAPPDY1WQ', 'altcoin-sideways-breakout-drift-btc-pair', 'Altcoin sideways-breakout drift (BTC pair)', 'event', 'IDEA', 'Range breakouts in major altcoin/BTC pairs show a recurring statistical pattern relevant to BTC-denominated flow.', 'Attention and liquidity rotation between BTC and alts follows recurring cyclical patterns tied to relative-strength breakouts.', 'This is the least developed candidate in the set — needs a dedicated event study before further investment.', '[{"kind":"internal","ref":"exchange-provided BTC-pair data","note":"breakout-conditioned forward return"}]', 'pdf_seed', 'EC-044', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVT39NZE44RCJC9HSA4', 'garch-volatility-regime-clustering', 'GARCH volatility-regime clustering', 'vol_regime', 'IDEA', 'BTC volatility exhibits strong GARCH clustering (alpha+beta approx 0.90), so regime persistence itself is a tradeable/conditioning signal.', 'Volatility clustering reflects persistent information flow and position-sizing feedback; once elevated, vol tends to stay elevated.', 'High persistence (alpha+beta near 1) implies near-integrated variance, making regime-switch timing (not just clustering) the harder, unsolved part.', '[{"kind":"paper","ref":"SSRN 5611392","note":"GARCH alpha+beta ~0.90 persistence"},{"kind":"paper","ref":"Takaishi 2021, PLOS ONE","note":"regime-switching GARCH"}]', 'pdf_seed', 'EC-045', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTARFA86V5X7HZBKNR', 'inverted-leverage-effect-btc-vol-asymmetry', 'Inverted leverage effect (BTC vol asymmetry)', 'vol_regime', 'IDEA', 'Unlike equities, BTC volatility reacts more to positive returns than negative ones (inverted asymmetry).', 'Crypto''s buy-side FOMO/momentum-chasing dynamic dominates over the equity-style leverage effect (where negative returns raise vol more).', 'Effect is documented on an earlier, smaller BTC market; needs reverification on the current, more institutionally-dominated market structure.', '[{"kind":"paper","ref":"Takaishi 2021, PLOS ONE","note":"inverted asymmetry: vol reacts more to positive returns"}]', 'pdf_seed', 'EC-046', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTGFFR7WVSEWTQD1H1', 'jump-dynamics-via-lee-mykland-detection', 'Jump dynamics via Lee-Mykland detection', 'vol_regime', 'IDEA', 'Statistically detected price jumps (Lee-Mykland test) cluster with order-flow-imbalance extremes, i.e. jumps are partly information-driven and partly liquidity-driven.', 'Jumps reflect either genuine information shocks or a liquidity air-pocket; distinguishing the two via OFI context could make jump risk partially forecastable.', 'Historical illustrative case (Mt. Gox) is an extreme, non-representative tail event.', '[{"kind":"internal","ref":"Lee-Mykland jump detection + Binance","note":"jump/OFI co-occurrence"}]', 'pdf_seed', 'EC-047', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVD13RNXRKX29EZKHF', 'session-open-close-volatility-seasonality', 'Session open/close volatility seasonality', 'vol_regime', 'IDEA', '5-minute realized volatility peaks around the 12:00 EST US equity session open/close, tracking traditional-market session boundaries.', 'Traditional-market session boundaries concentrate institutional order flow even in a 24/7 crypto market, since much liquidity still originates from US-hours desks.', 'Effect is one of the most robust in the set (durability 4, verifiability 4) but has limited standalone trading value (vol timing, not direction).', '[{"kind":"paper","ref":"ScienceDirect S1059056025006720","note":"5-min vol peaks at 12:00 EST session open/close"}]', 'pdf_seed', 'EC-048', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":4,"dataEase":5,"durability":4,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVXGTE75VG0KEJJWQJ', 'perp-spot-volume-ratio-leverage-regime', 'Perp/spot volume ratio leverage regime', 'cross_venue', 'IDEA', 'A high perp/spot traded-volume ratio signals leverage-dominated (fragile) markets prone to sharp reversals.', 'When derivatives volume dwarfs spot, price discovery is leverage-driven rather than cash-driven, raising the risk of a forced-deleveraging reversal.', 'Bybit''s perp share is already structurally very high (~92.5%) most of the time, so the ''high ratio'' threshold needs careful, venue-specific calibration.', '[{"kind":"internal","ref":"CCN / Kapar & Olmo","note":"perp/spot ratio ~60-80% typical range"}]', 'pdf_seed', 'EC-049', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVD995N0EWQNJPN961', 'cross-exchange-funding-divergence', 'Cross-exchange funding divergence', 'cross_venue', 'IDEA', 'Persistent funding-rate divergence between Binance/Bybit/OKX/Hyperliquid is informative about structural, venue-specific positioning imbalances.', 'Different venues attract different trader cohorts (retail vs. pro, regional bases), so persistent divergence reflects real segmentation, not just noise.', 'A cited industry view holds such divergences ''often reflect structural design differences... rather than arbitrageable mispricings'' — treat as a conditioning variable, not a standalone arbitrage.', '[{"kind":"internal","ref":"MetaMask commentary + exchange funding APIs","note":"cross-venue funding divergence"}]', 'pdf_seed', 'EC-050', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVY1ZVY7KBFNCEM9J9', 'hyperliquid-on-chain-positioning-transparency', 'Hyperliquid on-chain positioning transparency', 'cross_venue', 'IDEA', 'Hyperliquid''s fully on-chain order book/position data (unavailable on CEXs) gives an information edge on aggregate positioning.', 'Full transaction/position transparency on an L1 orderbook is structurally unique among major derivatives venues.', 'Hyperliquid is a newer, smaller venue; whether its positioning generalizes to broader market structure is unproven.', '[{"kind":"internal","ref":"coinmarketman + Hyperliquid public API","note":"on-chain position-distribution tracking"}]', 'pdf_seed', 'EC-051', '{"originality":5,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVN39CDZZYD8AV3WDM', 'kimchi-premium-korea-exchange-spread', 'Kimchi premium (Korea exchange spread)', 'cross_venue', 'IDEA', 'The Upbit/Bithumb vs. global exchange price premium (''kimchi premium'') reflects Korean retail sentiment and capital-control friction.', 'Korean won capital controls prevent frictionless arbitrage, so the premium is a persistent, regionally-segmented retail-sentiment gauge.', 'KRW/USD conversion adds an FX-timing dependency to the signal.', '[{"kind":"internal","ref":"Upbit/Bithumb + Binance + FRED KRW/USD","note":"premium-conditioned forward return"}]', 'pdf_seed', 'EC-052', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVDZ87W8YVT9GBH197', 'regional-cex-flow-divergence-coinbase-vs-binance', 'Regional CEX flow divergence (Coinbase vs. Binance)', 'cross_venue', 'IDEA', 'Coinbase-led moves (US hours) vs. Binance-led moves (global/Asia hours) have systematically different follow-through characteristics.', 'Regional flow originates from different trader cohorts (US institutional via Coinbase vs. global retail/leverage via Binance) with different persistence.', 'Attribution of ''which exchange led'' is itself a modeling choice sensitive to the lead-lag window used.', '[{"kind":"internal","ref":"cross-exchange aggTrades","note":"lead-exchange-conditioned forward return"}]', 'pdf_seed', 'EC-053', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVV50RRENG1E4EE0T9', 'eth-cross-sectional-feature-transfer-from-btc', 'ETH cross-sectional feature transfer from BTC', 'cross_venue', 'IDEA', 'Microstructure features (OFI, etc.) learned on BTC transfer to ETH and other large-cap assets, implying a scale-invariant microstructure mechanism.', 'If order-flow-imbalance dynamics are a structural feature of centralized limit order books rather than BTC-specific, the same feature ranking/SHAP importance should hold across assets.', 'Source study''s cross-asset set (BTC, LTC, ETC, ENJ, ROSE) is heterogeneous in liquidity; ETH-specific generalization still needs direct testing.', '[{"kind":"paper","ref":"arXiv:2602.00776","note":"feature ranking/SHAP stable across BTC, LTC, ETC, ENJ, ROSE"}]', 'pdf_seed', 'EC-054', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":4,"dataEase":4,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);
